# MoE Layer {{_id}}: {{n_experts}} experts, top-{{top_k}}
_moe{{_id}}_d = {{dim}}
_moe{{_id}}_hd = {{hidden_dim}}
_moe{{_id}}_ne = {{n_experts}}
_moe{{_id}}_k = {{top_k}}
# Router
_moe{{_id}}_w_gate = np.random.randn(_moe{{_id}}_ne, _moe{{_id}}_d).astype(np.float32) * {{init_std}}
# Expert weights (all experts stored as 3D tensors)
_moe{{_id}}_w_g = np.random.randn(_moe{{_id}}_ne, _moe{{_id}}_hd, _moe{{_id}}_d).astype(np.float32) * {{init_std}}
_moe{{_id}}_w_u = np.random.randn(_moe{{_id}}_ne, _moe{{_id}}_hd, _moe{{_id}}_d).astype(np.float32) * {{init_std}}
_moe{{_id}}_w_d = np.random.randn(_moe{{_id}}_ne, _moe{{_id}}_d, _moe{{_id}}_hd).astype(np.float32) * {{init_std}}
_moe{{_id}}_bs, _moe{{_id}}_sl, _ = {{input}}.shape
_moe{{_id}}_flat = {{input}}.reshape(-1, _moe{{_id}}_d)
_moe{{_id}}_ntok = _moe{{_id}}_flat.shape[0]
# Router scores -> top-k selection
_moe{{_id}}_logits = np.matmul(_moe{{_id}}_flat, _moe{{_id}}_w_gate.T)  # (ntok, n_experts)
_moe{{_id}}_topk_idx = np.argsort(_moe{{_id}}_logits, axis=-1)[:, -_moe{{_id}}_k:]  # (ntok, k)
_moe{{_id}}_topk_logits = np.take_along_axis(_moe{{_id}}_logits, _moe{{_id}}_topk_idx, axis=-1)
_moe{{_id}}_exp = np.exp(_moe{{_id}}_topk_logits - np.max(_moe{{_id}}_topk_logits, axis=-1, keepdims=True))
_moe{{_id}}_weights = _moe{{_id}}_exp / np.sum(_moe{{_id}}_exp, axis=-1, keepdims=True)
# Compute expert outputs (loop over tokens for clarity)
_moe{{_id}}_out = np.zeros((_moe{{_id}}_ntok, _moe{{_id}}_d), dtype=np.float32)
for _moe{{_id}}_i in range(_moe{{_id}}_ntok):
    for _moe{{_id}}_j in range(_moe{{_id}}_k):
        _moe{{_id}}_e = _moe{{_id}}_topk_idx[_moe{{_id}}_i, _moe{{_id}}_j]
        _moe{{_id}}_w = _moe{{_id}}_weights[_moe{{_id}}_i, _moe{{_id}}_j]
        _moe{{_id}}_gate_v = np.matmul(_moe{{_id}}_flat[_moe{{_id}}_i], _moe{{_id}}_w_g[_moe{{_id}}_e].T)
        _moe{{_id}}_up_v = np.matmul(_moe{{_id}}_flat[_moe{{_id}}_i], _moe{{_id}}_w_u[_moe{{_id}}_e].T)
        _moe{{_id}}_act = _moe{{_id}}_gate_v * (1.0 / (1.0 + np.exp(-_moe{{_id}}_gate_v)))  # SiLU
        _moe{{_id}}_expert_out = np.matmul(_moe{{_id}}_act * _moe{{_id}}_up_v, _moe{{_id}}_w_d[_moe{{_id}}_e].T)
        _moe{{_id}}_out[_moe{{_id}}_i] += _moe{{_id}}_w * _moe{{_id}}_expert_out
{{output}} = _moe{{_id}}_out.reshape(_moe{{_id}}_bs, _moe{{_id}}_sl, _moe{{_id}}_d)
